#include <iostream>
#include <vector>

int main()
{
    int n{};
    std::cin >> n;

    std::vector<int> v;
    for (int i = 0; i < n; ++i)
    {
        int x{};
        std::cin >> x;
        v.push_back(x);
    }

    int sum = 0;
    while (!v.empty())
    {
        sum += v.back();
        v.pop_back();
    }

    std::cout << "Sum: " << sum << '\n';

    return 0;
}

