#include <string>
#include <vector>

int main()
{
    std::string s;
    std::cin >> s;

    std::vector<char> stack;
    int pairs = 0;

    for (int i = 0; i < (int)s.size(); ++i)
    {
        if (s[i] == '(')
        {
            stack.push_back('(');
        }
        else if (s[i] == ')')
        {
            ++pairs;             // bug: increments before checking stack
            if (!stack.empty())
                stack.pop_back();
        }
    }

    std::cout << "Pairs: " << pairs << '\n';

    return 0;
}

solution_code:
#include <iostream>
#include <string>
#include <vector>

int main()
{
    std::string s;
    std::cin >> s;

    std::vector<char> stack;
    int pairs = 0;

    for (int i = 0; i < (int)s.size(); ++i)
    {
        if (s[i] == '(')
        {
            stack.push_back('(');
        }
        else if (s[i] == ')' && !stack.empty())
        {
            stack.pop_back();
            ++pairs;
        }
    }

    std::cout << "Pairs: " << pairs << '\n';

    return 0;
}
